              "java": "/*\n * Introducción a la codificación: muestra guiada completa\n * Objetivos de cobertura:\n * 1) ¿Qué es la codificación?\n * 2) Una breve historia de la programación\n * 3) Cómo el código se convierte en software en ejecución\n * 4) Cómo encaja la pila de software\n * 5) Trayectorias profesionales en tecnología\n * 6) Elegir tu camino de aprendizaje\n * 7) Elegir tu primer lenguaje de programación\n * 8) Configurar su entorno de desarrollo\n * 9) Tu primer programa\n * 10) Componentes básicos\n * 11) Depuración y resolución de problemas\n * 12) Control de versiones y conceptos básicos de colaboración\n * 13) Cómo leer documentación y mensajes de error\n * 14) Cómo hacer buenas preguntas técnicas\n * 15) Errores de los principiantes y cómo evitarlos\n * 16) Selección de proyectos y fundamentos de la cartera\n * 17) Sistemas de Estudio y Diseño de Hábitos\n * 18) Preparación para cursos y pasantías de informática\n * 19) Aprendizaje de los conceptos básicos del flujo de trabajo y del portafolio\n * 20) Plan inicial de 30 días\n * Estrategia de lectura:\n * - Siga los comentarios en línea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida después de cada paso lógico.\n */\nimport java.util.*;\n\npublic class IntroToCodingTopic18Set {\n    // Deterministic helper so learners can verify output after each edit.\n    static int guidedComputation(int seed) {\n        int total = 0;\n        for (int step = 1; step <= 5; step++) {\n            total += seed * step;\n            System.out.println(\"Step \" + step + \" -> running total: \" + total);\n        }\n        return total;\n    }\n\n    static void printTopicChecklist(List<String> topics) {\n        System.out.println(\"Lista de verificación de temas:\");\n        for (int i = 0; i < topics.size(); i++) {\n            System.out.println((i + 1) + \". \" + topics.get(i));\n        }\n    }\n\n    public static void main(String[] args) {\n        // Module context first so the learner sees where this snippet fits.\n        String moduleTitle = \"Introducción a la codificación\";\n        String moduleDescription = \"Comienza aquí si eres nuevo. Este módulo explica qué es la codificación, de dónde viene, qué carreras existen, cómo elegir su camino y su primer idioma, cómo configurar su entorno y los hábitos básicos que hacen que los principiantes tengan éxito.\";\n        String focusTopic = \"Preparación para cursos y pasantías de informática\";\n        List<String> topics = Arrays.asList(\"¿Qué es la codificación?\", \"Una breve historia de la programación\", \"Cómo el código se convierte en software en ejecución\", \"Cómo encaja la pila de software\", \"Trayectorias profesionales en tecnología\", \"Elegir su camino de aprendizaje\", \"Elegir su primer lenguaje de programación\", \"Configurar su entorno de desarrollo\", \"Tu primer programa\", \"Bloques de construcción básicos\", \"Depuración y resolución de problemas\", \"Control de versiones y conceptos básicos de colaboración\", \"Cómo leer documentación y mensajes de error\", \"Cómo hacer buenas preguntas técnicas\", \"Errores de los principiantes y cómo evitarlos\", \"Selección de proyectos y fundamentos de la cartera\", \"Sistemas de estudio y diseño de hábitos\", \"Preparación para cursos y pasantías de informática\", \"Aprendizaje de los conceptos básicos del flujo de trabajo y del portafolio\", \"Plan inicial de 30 días\");\n\n        System.out.println(\"Module: \" + moduleTitle);\n        System.out.println(\"Focus topic (18/20): \" + focusTopic);\n        System.out.println(moduleDescription);\n\n        // Print all module topics so this split example stays connected to the full module.\n        System.out.println(\"1. What Coding Is\");\n        System.out.println(\"2. A Short History of Programming\");\n        System.out.println(\"3. How Code Becomes Running Software\");\n        System.out.println(\"4. How the Software Stack Fits Together\");\n        System.out.println(\"5. Career Paths in Technology\");\n        System.out.println(\"6. Choosing Your Learning Path\");\n        System.out.println(\"7. Choosing Your First Programming Language\");\n        System.out.println(\"8. Setting Up Your Development Environment\");\n        System.out.println(\"9. Your First Program\");\n        System.out.println(\"10. Core Building Blocks\");\n        System.out.println(\"11. Debugging and Problem Solving\");\n        System.out.println(\"12. Version Control and Collaboration Basics\");\n        System.out.println(\"13. How to Read Documentation and Error Messages\");\n        System.out.println(\"14. How to Ask Good Technical Questions\");\n        System.out.println(\"15. Beginner Pitfalls and How to Avoid Them\");\n        System.out.println(\"16. Project Selection and Portfolio Foundations\");\n        System.out.println(\"17. Study Systems and Habit Design\");\n        System.out.println(\"18. Preparing for CS Coursework and Internships\");\n        System.out.println(\"19. Learning Workflow and Portfolio Basics\");\n        System.out.println(\"20. 30-Day Starter Plan\");\n\n        // Guided computation with explicit checkpoints and visible output.\n        int baseline = 54;\n        System.out.println(\"Baseline value: \" + baseline);\n        int result = guidedComputation(baseline);\n        System.out.println(\"Final computed result: \" + result);\n\n        // Reflection prompts are printed so output is always meaningful.\n        System.out.println(\"Reflection: explain how \" + focusTopic + \" influences implementation choices.\");\n        System.out.println(\"Practice: modify baseline, rerun, and compare output transitions.\");\n\n        // Summary line makes expected output deterministic for fallbacks.\n        System.out.println(\"Topic sample completed: \" + focusTopic);\n    }\n}",
              "cpp": "#include <iostream>\n#include <vector>\n#include <string>\nusing namespace std;\n\nint main() {\n    // Espejo C++ del ejemplo del módulo Java actualizado.\n    string moduleTitle = \"Introduction to Coding • Preparing for CS Coursework and Internships\";\n    string moduleDescription = \"Comienza aquí si eres nuevo. Este módulo explica qué es la codificación, de dónde viene, qué carreras existen, cómo elegir su camino y su primer idioma, cómo configurar su entorno y los hábitos básicos que hacen que los principiantes tengan éxito.\";\n    vector<string> topics = {\"¿Qué es la codificación?\", \"Una breve historia de la programación\", \"Cómo el código se convierte en software en ejecución\", \"Cómo encaja la pila de software\", \"Trayectorias profesionales en tecnología\", \"Elegir su camino de aprendizaje\"};\n    vector<string> javaSignals = {\"Lista de verificación de temas:\", \"1. What Coding Is\", \"2. A Short History of Programming\", \"3. How Code Becomes Running Software\", \"4. How the Software Stack Fits Together\", \"5. Career Paths in Technology\"};\n\n    // 1) Contexto del módulo de alto nivel\n    cout << \"Módulo en ejecución: \" << moduleTitle << \"\\n\";\n    cout << moduleDescription << \"\\n\";\n\n    // 2) Lista de verificación de temas para garantizar una cobertura conceptual completa\n    cout << \"Lista de verificación de temas:\\n\";\n    for (size_t i = 0; i < topics.size(); i++) {\n        cout << \"- \" << topics[i] << \"\\n\";\n    }\n\n    // 3) Marcadores de paridad de Java (reflejan importantes puntos de control de salida de Java)\n    cout << \"Puntos de control de paridad del ejemplo de Java:\\n\";\n    for (const auto& line : javaSignals) {\n        cout << \"* \" << line << \"\\n\";\n    }\n\n    cout << \"Muestra de paridad de C++ completada.\\n\";\n    return 0;\n}",
