              "java": "/*\n * Matrices y cadenas: muestra guiada completa\n * Objetivos de cobertura:\n * 1) recorrido de matriz\n * 2) Métodos de cadena\n * 3) Dos consejos\n * 4) Ventana corrediza\n * 5) Clasificación de matrices\n * Estrategia de lectura:\n * - Siga los comentarios en línea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida después de cada paso lógico.\n */\nimport java.util.Arrays;\n\npublic class ArraySortingSet {\n    public static void main(String[] args) {\n        int[] nums = {9, 4, 1, 7, 3, 8};\n        System.out.println(\"Before sort: \" + Arrays.toString(nums));\n        Arrays.sort(nums);\n        System.out.println(\"After sort:  \" + Arrays.toString(nums));\n        int target = 7;\n        int index = Arrays.binarySearch(nums, target);\n        System.out.println(\"Binary search for \" + target + \" -> index \" + index);\n    }\n}",
              "cpp": "#include <iostream>\n#include <vector>\n#include <string>\nusing namespace std;\n\nint main() {\n    // Espejo C++ del ejemplo del módulo Java actualizado.\n    string moduleTitle = \"Arrays and Strings • Array Sorting\";\n    string moduleDescription = \"Este tutorial analiza los ayudantes `findMax`, `reverseString` e `isPalindrome` para que pueda observar cómo los bucles, las protecciones de límites y los intercambios de dos punteros se combinan en utilidades reales de matriz/cadena.\";\n    vector<string> topics = {\"Recorrido de matriz\", \"Métodos de cadena\", \"Dos consejos\", \"Ventana corrediza\", \"Clasificación de matrices\"};\n    vector<string> javaSignals = {\"Ejemplo de Java ejecutado\"};\n\n    // 1) Contexto del módulo de alto nivel\n    cout << \"Módulo en ejecución: \" << moduleTitle << \"\\n\";\n    cout << moduleDescription << \"\\n\";\n\n    // 2) Lista de verificación de temas para garantizar una cobertura conceptual completa\n    cout << \"Lista de verificación de temas:\\n\";\n    for (size_t i = 0; i < topics.size(); i++) {\n        cout << \"- \" << topics[i] << \"\\n\";\n    }\n\n    // 3) Marcadores de paridad de Java (reflejan importantes puntos de control de salida de Java)\n    cout << \"Puntos de control de paridad del ejemplo de Java:\\n\";\n    for (const auto& line : javaSignals) {\n        cout << \"* \" << line << \"\\n\";\n    }\n\n    cout << \"Muestra de paridad de C++ completada.\\n\";\n    return 0;\n}",
