              "java": "/*\n * Programación dinámica: muestra guiada completa\n * Objetivos de cobertura:\n * 1) Memorización\n * 2) Tabulación\n * 3) Subestructura óptima\n * 4) Subproblemas superpuestos\n * Estrategia de lectura:\n * - Siga los comentarios en línea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida después de cada paso lógico.\n */\nimport java.util.*;\n\npublic class DynamicProgrammingTopic3Set {\n    // Deterministic helper so learners can verify output after each edit.\n    static int guidedComputation(int seed) {\n        int total = 0;\n        for (int step = 1; step <= 5; step++) {\n            total += seed * step;\n            System.out.println(\"Step \" + step + \" -> running total: \" + total);\n        }\n        return total;\n    }\n\n    static void printTopicChecklist(List<String> topics) {\n        System.out.println(\"Lista de verificación de temas:\");\n        for (int i = 0; i < topics.size(); i++) {\n            System.out.println((i + 1) + \". \" + topics.get(i));\n        }\n    }\n\n    public static void main(String[] args) {\n        // Module context first so the learner sees where this snippet fits.\n        String moduleTitle = \"Programación dinámica\";\n        String moduleDescription = \"El mapa de Fibonacci memorizado, la matriz LIS DP y la tabla de mochila 0/1 se detallan paso a paso para que pueda seguir cómo se almacenan en caché los estados, se eligen las transiciones y se leen las respuestas.\";\n        String focusTopic = \"Subestructura óptima\";\n        List<String> topics = Arrays.asList(\"Memoization\", \"Tabulation\", \"Subestructura óptima\", \"Subproblemas superpuestos\");\n\n        System.out.println(\"Module: \" + moduleTitle);\n        System.out.println(\"Focus topic (3/4): \" + focusTopic);\n        System.out.println(moduleDescription);\n\n        // Print all module topics so this split example stays connected to the full module.\n        System.out.println(\"1. Memoization\");\n        System.out.println(\"2. Tabulation\");\n        System.out.println(\"3. Optimal Substructure\");\n        System.out.println(\"4. Overlapping Subproblems\");\n\n        // Guided computation with explicit checkpoints and visible output.\n        int baseline = 9;\n        System.out.println(\"Baseline value: \" + baseline);\n        int result = guidedComputation(baseline);\n        System.out.println(\"Final computed result: \" + result);\n\n        // Reflection prompts are printed so output is always meaningful.\n        System.out.println(\"Reflection: explain how \" + focusTopic + \" influences implementation choices.\");\n        System.out.println(\"Practice: modify baseline, rerun, and compare output transitions.\");\n\n        // Summary line makes expected output deterministic for fallbacks.\n        System.out.println(\"Topic sample completed: \" + focusTopic);\n    }\n}",
              "cpp": "#include <iostream>\n#include <vector>\n#include <string>\nusing namespace std;\n\nint main() {\n    // Espejo C++ del ejemplo del módulo Java actualizado.\n    string moduleTitle = \"Dynamic Programming • Optimal Substructure\";\n    string moduleDescription = \"El mapa de Fibonacci memorizado, la matriz LIS DP y la tabla de mochila 0/1 se detallan paso a paso para que pueda seguir cómo se almacenan en caché los estados, se eligen las transiciones y se leen las respuestas.\";\n    vector<string> topics = {\"Memoization\", \"Tabulation\", \"Subestructura óptima\", \"Subproblemas superpuestos\"};\n    vector<string> javaSignals = {\"Lista de verificación de temas:\", \"1. Memoization\", \"2. Tabulation\", \"3. Optimal Substructure\", \"4. Overlapping Subproblems\", \"Practice: modify baseline, rerun, and compare output transitions.\"};\n\n    // 1) Contexto del módulo de alto nivel\n    cout << \"Módulo en ejecución: \" << moduleTitle << \"\\n\";\n    cout << moduleDescription << \"\\n\";\n\n    // 2) Lista de verificación de temas para garantizar una cobertura conceptual completa\n    cout << \"Lista de verificación de temas:\\n\";\n    for (size_t i = 0; i < topics.size(); i++) {\n        cout << \"- \" << topics[i] << \"\\n\";\n    }\n\n    // 3) Marcadores de paridad de Java (reflejan importantes puntos de control de salida de Java)\n    cout << \"Puntos de control de paridad del ejemplo de Java:\\n\";\n    for (const auto& line : javaSignals) {\n        cout << \"* \" << line << \"\\n\";\n    }\n\n    cout << \"Muestra de paridad de C++ completada.\\n\";\n    return 0;\n}",
              "python": "# Espejo de Python del ejemplo del módulo Java actualizado.\n# Este guión mantiene los mismos puntos de control conceptuales y los imprime claramente.\n\ndef run_module_demo():\n    module_title = \"Dynamic Programming • Optimal Substructure\"\n    module_description = \"El mapa de Fibonacci memorizado, la matriz LIS DP y la tabla de mochila 0/1 se detallan paso a paso para que pueda seguir cómo se almacenan en caché los estados, se eligen las transiciones y se leen las respuestas.\"\n    topics = [\"Memoization\", \"Tabulation\", \"Subestructura óptima\", \"Subproblemas superpuestos\"]\n    java_signals = [\"Lista de verificación de temas:\", \"1. Memoization\", \"2. Tabulation\", \"3. Optimal Substructure\", \"4. Overlapping Subproblems\", \"Practice: modify baseline, rerun, and compare output transitions.\"]\n\n    # 1) Contexto del módulo de alto nivel\n    print(f\"Módulo en ejecución: {module_title}\")\n    print(module_description)\n\n    # 2) Lista de verificación de temas para una cobertura completa\n    print(\"Lista de verificación de temas:\")\n    for topic in topics:\n        print(f\"- {tema}\")\n\n    # 3) Marcadores de paridad de Java para confirmar la intención alineada\n    print(\"Puntos de control de paridad del ejemplo de Java:\")\n    for line in java_signals:\n        print(f\"* {línea}\")\n\n    print(\"Muestra de paridad de Python completada.\")\n\nif __name__ == \"__main__\":\n    run_module_demo()\n",
