              "cpp": "#include <iostream>\n#include <vector>\n#include <string>\nusing namespace std;\n\nint main() {\n    // Espejo C++ del ejemplo del módulo Java actualizado.\n    string moduleTitle = \"Propositional Logic and Proof Basics • Truth Tables\";\n    string moduleDescription = \"Los ayudantes de valor de verdad para implicación, conjunción y bicondicional se rastrean en un mini corredor de tabla de verdad para que pueda conectar la lógica simbólica con el razonamiento ejecutable.\";\n    vector<string> topics = {\"Propositions\", \"Tablas de verdad\", \"Implication\", \"Equivalencia lógica\", \"Prueba directa\"};\n    vector<string> javaSignals = {\"Lista de verificación de temas:\", \"1. Propositions\", \"2. Truth Tables\", \"3. Implication\", \"4. Logical Equivalence\", \"5. Direct Proof\"};\n\n    // 1) Contexto del módulo de alto nivel\n    cout << \"Módulo en ejecución: \" << moduleTitle << \"\\n\";\n    cout << moduleDescription << \"\\n\";\n\n    // 2) Lista de verificación de temas para garantizar una cobertura conceptual completa\n    cout << \"Lista de verificación de temas:\\n\";\n    for (size_t i = 0; i < topics.size(); i++) {\n        cout << \"- \" << topics[i] << \"\\n\";\n    }\n\n    // 3) Marcadores de paridad de Java (reflejan importantes puntos de control de salida de Java)\n    cout << \"Puntos de control de paridad del ejemplo de Java:\\n\";\n    for (const auto& line : javaSignals) {\n        cout << \"* \" << line << \"\\n\";\n    }\n\n    cout << \"Muestra de paridad de C++ completada.\\n\";\n    return 0;\n}",
