              "cpp": "#include <iostream>\n#include <vector>\n#include <string>\nusing namespace std;\n\nint main() {\n    // Espejo C++ del ejemplo del módulo Java actualizado.\n    string moduleTitle = \"Advanced Tree Structures • Tree Rotations\";\n    string moduleDescription = \"La tubería de inserción AVL actualiza las alturas, verifica los factores de equilibrio y activa las rotaciones correctas antes de que un recorrido en orden verifique que el árbol permaneció ordenado.\";\n    vector<string> topics = {\"Árboles AVL\", \"Árboles rojo-negros\", \"B-Trees\", \"Árboles extendidos\", \"Rotaciones de árboles\"};\n    vector<string> javaSignals = {\"Lista de verificación de temas:\", \"1. AVL Trees\", \"2. Red-Black Trees\", \"3. B-Trees\", \"4. Splay Trees\", \"5. Tree Rotations\"};\n\n    // 1) Contexto del módulo de alto nivel\n    cout << \"Módulo en ejecución: \" << moduleTitle << \"\\n\";\n    cout << moduleDescription << \"\\n\";\n\n    // 2) Lista de verificación de temas para garantizar una cobertura conceptual completa\n    cout << \"Lista de verificación de temas:\\n\";\n    for (size_t i = 0; i < topics.size(); i++) {\n        cout << \"- \" << topics[i] << \"\\n\";\n    }\n\n    // 3) Marcadores de paridad de Java (reflejan importantes puntos de control de salida de Java)\n    cout << \"Puntos de control de paridad del ejemplo de Java:\\n\";\n    for (const auto& line : javaSignals) {\n        cout << \"* \" << line << \"\\n\";\n    }\n\n    cout << \"Muestra de paridad de C++ completada.\\n\";\n    return 0;\n}",
