              "javascript": "// Espejo de JavaScript del ejemplo del módulo Java actualizado.\n// Esto conserva los mismos puntos de control de instrucción y resultados visibles.\n(function runModuleDemo() {\n    const moduleTitle = \"Assembly Arrays, Strings, and Basic I/O • Array Traversal\";\n    const moduleDescription = \"El puntero que pasa por encima de matrices, escaneos de cadenas terminadas en nulo y patrones mínimos de E/S se dividen en pequeños ejemplos para que el recorrido de datos en el ensamblaje se sienta concreto.\";\n    const topics = [\"Aritmética de punteros\", \"Recorrido de matriz\", \"Cadenas terminadas en nulo\", \"Llamadas al sistema\", \"Acceso a bytes/palabras\"];\n    const javaSignals = [\"Lista de verificación de temas:\", \"1. Pointer Arithmetic\", \"2. Array Traversal\", \"3. Null-Terminated Strings\", \"4. System Calls\", \"5. Byte/Word Access\"];\n\n    // 1) Contexto del módulo de alto nivel\n    console.log(\"Módulo en ejecución: \" + moduleTitle);\n    console.log(moduleDescription);\n\n    // 2) Lista de verificación de temas para una cobertura conceptual completa\n    console.log(\"Lista de verificación de temas:\");\n    topics.forEach((topic) => console.log(\"- \" + topic));\n\n    // 3) Marcadores de paridad de Java para alinearse con la muestra canónica de Java\n    console.log(\"Puntos de control de paridad del ejemplo de Java:\");\n    javaSignals.forEach((line) => console.log(\"* \" + line));\n\n    console.log(\"Muestra de paridad de JavaScript completada.\");\n})();\n",
              "assembly": "; Assembly Arrays, Strings, and Basic I/O - Array Traversal\n; Topic 2 of 5\n; Guided assembly sample for module-card viewing and output fallback notes.\n; Goal: trace registers, memory changes, and branch flow step by step.\n; Focus checklist:\n; 1) Initialize registers safely\n; 2) Execute deterministic operations\n; 3) Observe control flow and exit cleanly\n\nsection .data\n    out_msg db \"Assembly topic: Array Traversal\", 10\n    out_len equ $ - out_msg\n\nsection .text\n    global _start\n_start:\n    ; Initialize registers\n    xor rax, rax\n    mov rbx, 3\n    add rax, rbx\n\n    ; Print topic message (Linux syscall write)\n    mov rax, 1\n    mov rdi, 1\n    mov rsi, out_msg\n    mov rdx, out_len\n    syscall\n\n    ; Exit (Linux syscall exit)\n    mov rax, 60\n    xor rdi, rdi\n    syscall\n"
