              "java": "/*\n * Conceptos básicos de Git y flujo de trabajo de colaboración: muestra guiada completa\n * Objetivos de cobertura:\n * 1) Configuración del repositorio\n * 2) Puesta en escena y compromisos\n * 3) Ramificación y fusión\n * 4) Conceptos básicos de extracción/rebase\n * 5) Fusionar conceptos básicos de conflictos\n * 6) Colaboración remota\n * 7) Deshacer de forma segura con Restaurar/Revertir\n * Estrategia de lectura:\n * - Siga los comentarios en línea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida después de cada paso lógico.\n */\nimport java.util.*;\n\npublic class GitBasicsWorkflowTopic5Set {\n    static void section(String label) {\n        System.out.println(\"\\n=== \" + label + \" ===\");\n    }\n\n    static void command(String cmd, String... output) {\n        System.out.println(\"$ \" + cmd);\n        if (output.length == 0) {\n            System.out.println(\"  (sin salida estándar)\");\n            return;\n        }\n        for (String line : output) {\n            System.out.println(\"  \" + line);\n        }\n    }\n\n    public static void main(String[] args) {\n        section(\"Git Terminal Simulation\");\n        System.out.println(\"Module: Git Basics and Collaboration Workflow\");\n        System.out.println(\"Focus topic (5/7): Merge Conflict Basics\");\n        System.out.println(\"Objective: Resolve conflicts intentionally and finish the integration cleanly.\");\n        System.out.println(\"Topic map:\");\n        System.out.println(\"1. Repository Setup\");\n        System.out.println(\"2. Staging and Commits\");\n        System.out.println(\"3. Branching and Merging\");\n        System.out.println(\"4. Pull/Rebase Basics\");\n        System.out.println(\"5. Merge Conflict Basics\");\n        System.out.println(\"6. Remote Collaboration\");\n        System.out.println(\"7. Safe Undo with Restore/Revert\");\n\n        section(\"Fusionar conceptos básicos de conflictos\");\n        command(\"git merge feature/profile-layout\", \"Auto-merging profile.html\", \"CONFLICT (content): Merge conflict in profile.html\");\n        command(\"estado de git\", \"You have unmerged paths.\", \"both modified: profile.html\");\n        command(\"# edit profile.html and remove <<<<<<< ======= >>>>>>> markers\", \"File manually resolved\");\n        command(\"git add profile.html\", \"Conflict marked as resolved\");\n        command(\"git commit -m \\\"fix: resolve profile layout merge conflict\\\"\", \"[main 7ce31a1] fix: resolve profile layout merge conflict\");\n\n        section(\"Summary\");\n        System.out.println(\"Conflict resolved by editing final content, then staging and committing resolution.\");\n        System.out.println(\"Practice: replay these commands in a real terminal with a throwaway repo.\");\n        System.out.println(\"Git topic walkthrough complete: Merge Conflict Basics\");\n    }\n}",
