              "javascript": "// Espejo de JavaScript del ejemplo del módulo Java actualizado.\n// Esto conserva los mismos puntos de control de instrucción y resultados visibles.\n(function runModuleDemo() {\n    const moduleTitle = \"Git Basics and Collaboration Workflow • Safe Undo with Restore/Revert\";\n    const moduleDescription = \"Este módulo inicial explica la configuración del repositorio, la puesta en escena, las confirmaciones, las bifurcaciones, el flujo de extracción/fusión, los conceptos básicos de resolución de conflictos y los comandos de deshacer seguros que puede usar en proyectos de equipo reales.\";\n    const topics = [\"Configuración del repositorio\", \"Puesta en escena y compromisos\", \"Ramificación y fusión\", \"Conceptos básicos de extracción/rebase\", \"Fusionar conceptos básicos de conflictos\", \"Colaboración remota\"];\n    const javaSignals = [\"(sin salida estándar)\", \"Module: Git Basics and Collaboration Workflow\", \"Focus topic (7/7): Safe Undo with Restore/Revert\", \"Objective: Use restore for local cleanup and revert for shared-history undo.\", \"Topic map:\", \"1. Repository Setup\"];\n\n    // 1) Contexto del módulo de alto nivel\n    console.log(\"Módulo en ejecución: \" + moduleTitle);\n    console.log(moduleDescription);\n\n    // 2) Lista de verificación de temas para una cobertura conceptual completa\n    console.log(\"Lista de verificación de temas:\");\n    topics.forEach((topic) => console.log(\"- \" + topic));\n\n    // 3) Marcadores de paridad de Java para alinearse con la muestra canónica de Java\n    console.log(\"Puntos de control de paridad del ejemplo de Java:\");\n    javaSignals.forEach((line) => console.log(\"* \" + line));\n\n    console.log(\"Muestra de paridad de JavaScript completada.\");\n})();\n"
