              "java": "/*\n * Conceptos básicos de subprocesos múltiples: muestra guiada completa\n * Objetivos de cobertura:\n * 1) Clase de hilo\n * 2) Interfaz ejecutable\n * 3) Sincronización\n * 4) Seguridad del hilo\n * Estrategia de lectura:\n * - Siga los comentarios en línea de arriba a abajo.\n * - Ejecute una vez, luego edite un concepto a la vez y vuelva a ejecutar.\n * - Verificar la salida después de cada paso lógico.\n */\nimport java.util.*;\n\npublic class MultithreadingTopic4Set {\n    // Deterministic helper so learners can verify output after each edit.\n    static int guidedComputation(int seed) {\n        int total = 0;\n        for (int step = 1; step <= 5; step++) {\n            total += seed * step;\n            System.out.println(\"Step \" + step + \" -> running total: \" + total);\n        }\n        return total;\n    }\n\n    static void printTopicChecklist(List<String> topics) {\n        System.out.println(\"Lista de verificación de temas:\");\n        for (int i = 0; i < topics.size(); i++) {\n            System.out.println((i + 1) + \". \" + topics.get(i));\n        }\n    }\n\n    public static void main(String[] args) {\n        // Module context first so the learner sees where this snippet fits.\n        String moduleTitle = \"Conceptos básicos de subprocesos múltiples\";\n        String moduleDescription = \"Un \"Contador\" implementa Runnable, imprime el progreso dentro de \"ejecutar\" y se inician dos subprocesos en \"principal\", lo que le permite rastrear la programación, el sueño y la interrupción elegante.\";\n        String focusTopic = \"Seguridad del hilo\";\n        List<String> topics = Arrays.asList(\"Clase de hilo\", \"Interfaz ejecutable\", \"Synchronization\", \"Seguridad del hilo\");\n\n        System.out.println(\"Module: \" + moduleTitle);\n        System.out.println(\"Focus topic (4/4): \" + focusTopic);\n        System.out.println(moduleDescription);\n\n        // Print all module topics so this split example stays connected to the full module.\n        System.out.println(\"1. Thread Class\");\n        System.out.println(\"2. Runnable Interface\");\n        System.out.println(\"3. Synchronization\");\n        System.out.println(\"4. Thread Safety\");\n\n        // Guided computation with explicit checkpoints and visible output.\n        int baseline = 12;\n        System.out.println(\"Baseline value: \" + baseline);\n        int result = guidedComputation(baseline);\n        System.out.println(\"Final computed result: \" + result);\n\n        // Reflection prompts are printed so output is always meaningful.\n        System.out.println(\"Reflection: explain how \" + focusTopic + \" influences implementation choices.\");\n        System.out.println(\"Practice: modify baseline, rerun, and compare output transitions.\");\n\n        // Summary line makes expected output deterministic for fallbacks.\n        System.out.println(\"Topic sample completed: \" + focusTopic);\n    }\n}",
              "cpp": "#include <iostream>\n#include <vector>\n#include <string>\nusing namespace std;\n\nint main() {\n    // Espejo C++ del ejemplo del módulo Java actualizado.\n    string moduleTitle = \"Multithreading Basics • Thread Safety\";\n    string moduleDescription = \"Un \"Contador\" implementa Runnable, imprime el progreso dentro de \"ejecutar\" y se inician dos subprocesos en \"principal\", lo que le permite rastrear la programación, el sueño y la interrupción elegante.\";\n    vector<string> topics = {\"Clase de hilo\", \"Interfaz ejecutable\", \"Synchronization\", \"Seguridad del hilo\"};\n    vector<string> javaSignals = {\"Lista de verificación de temas:\", \"1. Thread Class\", \"2. Runnable Interface\", \"3. Synchronization\", \"4. Thread Safety\", \"Practice: modify baseline, rerun, and compare output transitions.\"};\n\n    // 1) Contexto del módulo de alto nivel\n    cout << \"Módulo en ejecución: \" << moduleTitle << \"\\n\";\n    cout << moduleDescription << \"\\n\";\n\n    // 2) Lista de verificación de temas para garantizar una cobertura conceptual completa\n    cout << \"Lista de verificación de temas:\\n\";\n    for (size_t i = 0; i < topics.size(); i++) {\n        cout << \"- \" << topics[i] << \"\\n\";\n    }\n\n    // 3) Marcadores de paridad de Java (reflejan importantes puntos de control de salida de Java)\n    cout << \"Puntos de control de paridad del ejemplo de Java:\\n\";\n    for (const auto& line : javaSignals) {\n        cout << \"* \" << line << \"\\n\";\n    }\n\n    cout << \"Muestra de paridad de C++ completada.\\n\";\n    return 0;\n}",
              "python": "# Espejo de Python del ejemplo del módulo Java actualizado.\n# Este guión mantiene los mismos puntos de control conceptuales y los imprime claramente.\n\ndef run_module_demo():\n    module_title = \"Multithreading Basics • Thread Safety\"\n    module_description = \"Un \"Contador\" implementa Runnable, imprime el progreso dentro de \"ejecutar\" y se inician dos subprocesos en \"principal\", lo que le permite rastrear la programación, el sueño y la interrupción elegante.\"\n    topics = [\"Clase de hilo\", \"Interfaz ejecutable\", \"Synchronization\", \"Seguridad del hilo\"]\n    java_signals = [\"Lista de verificación de temas:\", \"1. Thread Class\", \"2. Runnable Interface\", \"3. Synchronization\", \"4. Thread Safety\", \"Practice: modify baseline, rerun, and compare output transitions.\"]\n\n    # 1) Contexto del módulo de alto nivel\n    print(f\"Módulo en ejecución: {module_title}\")\n    print(module_description)\n\n    # 2) Lista de verificación de temas para una cobertura completa\n    print(\"Lista de verificación de temas:\")\n    for topic in topics:\n        print(f\"- {tema}\")\n\n    # 3) Marcadores de paridad de Java para confirmar la intención alineada\n    print(\"Puntos de control de paridad del ejemplo de Java:\")\n    for line in java_signals:\n        print(f\"* {línea}\")\n\n    print(\"Muestra de paridad de Python completada.\")\n\nif __name__ == \"__main__\":\n    run_module_demo()\n",
              "javascript": "// Espejo de JavaScript del ejemplo del módulo Java actualizado.\n// Esto conserva los mismos puntos de control de instrucción y resultados visibles.\n(function runModuleDemo() {\n    const moduleTitle = \"Multithreading Basics • Thread Safety\";\n    const moduleDescription = \"Un \"Contador\" implementa Runnable, imprime el progreso dentro de \"ejecutar\" y se inician dos subprocesos en \"principal\", lo que le permite rastrear la programación, el sueño y la interrupción elegante.\";\n    const topics = [\"Clase de hilo\", \"Interfaz ejecutable\", \"Synchronization\", \"Seguridad del hilo\"];\n    const javaSignals = [\"Lista de verificación de temas:\", \"1. Thread Class\", \"2. Runnable Interface\", \"3. Synchronization\", \"4. Thread Safety\", \"Practice: modify baseline, rerun, and compare output transitions.\"];\n\n    // 1) Contexto del módulo de alto nivel\n    console.log(\"Módulo en ejecución: \" + moduleTitle);\n    console.log(moduleDescription);\n\n    // 2) Lista de verificación de temas para una cobertura conceptual completa\n    console.log(\"Lista de verificación de temas:\");\n    topics.forEach((topic) => console.log(\"- \" + topic));\n\n    // 3) Marcadores de paridad de Java para alinearse con la muestra canónica de Java\n    console.log(\"Puntos de control de paridad del ejemplo de Java:\");\n    javaSignals.forEach((line) => console.log(\"* \" + line));\n\n    console.log(\"Muestra de paridad de JavaScript completada.\");\n})();\n"
